import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define custom CUDA kernel for optimized min reduction
min_reduction_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <limits>

template<typename scalar_t>
__global__ void min_reduction_dim1_kernel(
    const scalar_t* __restrict__ input,
    scalar_t* __restrict__ output,
    const int batch_size,
    const int dim1,
    const int dim2
) {
    // Reduce over dim1 (dimension 1)
    const int batch = blockIdx.x;
    const int col = threadIdx.x;
    const int stride = blockDim.x;

    if (col >= dim2) return;

    scalar_t thread_min = std::numeric_limits<scalar_t>::max();

    // Each thread processes all rows for its column
    for (int row = 0; row < dim1; row++) {
        int idx = (batch * dim1 + row) * dim2 + col;
        scalar_t val = input[idx];
        if (val < thread_min) {
            thread_min = val;
        }
    }

    // Write thread result directly to output
    output[batch * dim2 + col] = thread_min;
}

template<typename scalar_t>
__global__ void min_reduction_dim2_kernel(
    const scalar_t* __restrict__ input,
    scalar_t* __restrict__ output,
    const int batch_size,
    const int dim1,
    const int dim2
) {
    // Reduce over dim2 (dimension 2)
    const int batch = blockIdx.x;
    const int row = threadIdx.x;
    const int stride = blockDim.x;

    if (row >= dim1) return;

    scalar_t thread_min = std::numeric_limits<scalar_t>::max();

    // Each thread processes all columns for its row
    for (int col = 0; col < dim2; col++) {
        int idx = (batch * dim1 + row) * dim2 + col;
        scalar_t val = input[idx];
        if (val < thread_min) {
            thread_min = val;
        }
    }

    // Write thread result directly to output
    output[batch * dim1 + row] = thread_min;
}

template<typename scalar_t>
__global__ void min_reduction_dim0_kernel(
    const scalar_t* __restrict__ input,
    scalar_t* __restrict__ output,
    const int batch_size,
    const int dim1,
    const int dim2
) {
    // Reduce over batch dimension (dimension 0)
    const int row = blockIdx.x;
    const int col = threadIdx.x;

    if (col >= dim2) return;

    scalar_t thread_min = std::numeric_limits<scalar_t>::max();

    // Each thread processes all batches for its (row, col) position
    for (int batch = 0; batch < batch_size; batch++) {
        int idx = (batch * dim1 + row) * dim2 + col;
        scalar_t val = input[idx];
        if (val < thread_min) {
            thread_min = val;
        }
    }

    // Write thread result directly to output
    output[row * dim2 + col] = thread_min;
}

torch::Tensor min_reduction_cuda(torch::Tensor input, int dim) {
    auto sizes = input.sizes();
    int batch_size = sizes[0];
    int dim1 = sizes[1];
    int dim2 = sizes[2];

    // Calculate output shape
    torch::Tensor output;
    if (dim == 0) {
        output = torch::empty({dim1, dim2}, input.options());
    } else if (dim == 1) {
        output = torch::empty({batch_size, dim2}, input.options());
    } else if (dim == 2) {
        output = torch::empty({batch_size, dim1}, input.options());
    } else {
        throw std::runtime_error("Invalid reduction dimension");
    }

    // Choose kernel based on reduction dimension
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "min_reduction", ([&] {
        if (dim == 0) {
            // Reduce over batch dimension
            dim3 grid(dim1, 1, 1);
            int block_size = min(dim2, 1024);

            min_reduction_dim0_kernel<scalar_t><<<grid, block_size>>>(
                input.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                batch_size,
                dim1,
                dim2
            );
        } else if (dim == 1) {
            // Reduce over dim1
            dim3 grid(batch_size, 1, 1);
            int block_size = min(dim2, 1024);

            min_reduction_dim1_kernel<scalar_t><<<grid, block_size>>>(
                input.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                batch_size,
                dim1,
                dim2
            );
        } else if (dim == 2) {
            // Reduce over dim2
            dim3 grid(batch_size, 1, 1);
            int block_size = min(dim1, 1024);

            min_reduction_dim2_kernel<scalar_t><<<grid, block_size>>>(
                input.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                batch_size,
                dim1,
                dim2
            );
        }
    }));

    cudaDeviceSynchronize();
    return output;
}
"""

min_reduction_cpp_source = "torch::Tensor min_reduction_cuda(torch::Tensor input, int dim);"

# Compile the inline CUDA code
min_reduction = load_inline(
    name="min_reduction",
    cpp_sources=min_reduction_cpp_source,
    cuda_sources=min_reduction_source,
    functions=["min_reduction_cuda"],
    verbose=False,
    extra_cflags=[""],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    """
    Optimized model that performs min reduction over a specific dimension using custom CUDA kernel.
    """
    def __init__(self, dim: int):
        """
        Initializes the model with the dimension to reduce over.

        Args:
            dim (int): The dimension to reduce over.
        """
        super(ModelNew, self).__init__()
        self.dim = dim
        self.min_reduction = min_reduction

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies min reduction over the specified dimension to the input tensor.

        Args:
            x (torch.Tensor): Input tensor.

        Returns:
            torch.Tensor: Output tensor after min reduction over the specified dimension.
        """
        return self.min_reduction.min_reduction_cuda(x, self.dim)

