def generate_inputs(device):
    batch_size, dim1, dim2 = 16, 256, 256
    # Create tensor where value = row*1000 + col*10 + batch
    # This ensures each (row, col, batch) has unique value
    # and minimum for each (row, col) across batches is at batch=0
    x = torch.zeros(batch_size, dim1, dim2, device=device)
    for b in range(batch_size):
        for r in range(dim1):
            for c in range(dim2):
                x[b, r, c] = r * 1000 + c * 10 + b
    return (x,)

